nibiru/repo/nibiru/x/evm/keeper/keeper.g.source:
type Keeper struct {
	cdc codec.BinaryCodec
	// storeKey: For persistent storage of EVM state.
	storeKey storetypes.StoreKey
	// transientKey: Store key that resets every block during Commit
	transientKey storetypes.StoreKey

	// EvmState isolates the key-value stores (collections) for the x/evm module.
	EvmState EvmState

	// FunTokens isolates the key-value stores (collections) for fungible token
	// mappings.
	FunTokens FunTokenState

	// the address capable of executing a MsgUpdateParams message. Typically,
	// this should be the x/gov module account.
	authority sdk.AccAddress

	Bank          *NibiruBankKeeper
	accountKeeper evm.AccountKeeper
	stakingKeeper evm.StakingKeeper

	// precompiles is the set of active precompiled contracts used in the EVM.
	// Precompiles are special, built-in contract interfaces that exist at
	// predefined address and run custom logic outside of what is possible only
	// in Solidity.
	precompiles omap.SortedMap[gethcommon.Address, vm.PrecompiledContract]

	// tracer: Configures the output type for a geth `vm.EVMLogger`. Tracer types
	// include "access_list", "json", "struct", and "markdown". If any other
	// value is used, a no operation tracer is set.
	tracer string
}

nibiru/repo/nibiru/x/devgas/v1/keeper/ke.source:
type Keeper struct {
	storeKey storetypes.StoreKey
	cdc      codec.BinaryCodec

	bankKeeper    devgastypes.BankKeeper
	wasmKeeper    wasmkeeper.Keeper
	accountKeeper devgastypes.AccountKeeper

	// feeCollectorName is the name of x/auth module's fee collector module
	// account, "fee_collector", which collects transaction fees for distribution
	// to all stakers.
	//
	// See the `[AllocateTokens]` function from x/distribution to learn more.
	// [AllocateTokens]: https://github.com/cosmos/cosmos-sdk/blob/v0.50.3/x/distribution/keeper/allocation.go
	feeCollectorName string

	// DevGasStore: IndexedMap
	//  - primary key (PK): Contract address. The contract is the primary key
	//  because there's exactly one deployer and withdrawer.
	//  - value (V): FeeShare value saved into state.
	//  - indexers (I):  Indexed by deployer and withdrawer
	DevGasStore collections.IndexedMap[string, devgastypes.FeeShare, DevGasIndexes]

	ModuleParams collections.Item[devgastypes.ModuleParams]

	// the address capable of executing a MsgUpdateParams message. Typically,
	// this should be the x/gov module account.
	authority string
}

nibiru/repo/nibiru/x/inflation/keeper/ke.source:
type Keeper struct {
	cdc      codec.BinaryCodec
	storeKey storetypes.StoreKey

	accountKeeper types.AccountKeeper
	bankKeeper    types.BankKeeper
	distrKeeper   types.DistrKeeper
	stakingKeeper types.StakingKeeper
	sudoKeeper    types.SudoKeeper
	// feeCollectorName is the name of x/auth module's fee collector module
	// account, "fee_collector", which collects transaction fees for distribution
	// to all stakers.
	// By sending staking inflation to the fee collector, the tokens are properly
	// distributed to validator operators and their delegates.
	// See the `[AllocateTokens]` function from x/distribution to learn more.
	// [AllocateTokens]: https://github.com/cosmos/cosmos-sdk/blob/v0.50.3/x/distribution/keeper/allocation.go
	feeCollectorName string

	// CurrentPeriod: Strictly increasing counter for the inflation "period".
	CurrentPeriod collections.Sequence

	// NumSkippedEpochs: Strictly increasing counter for the number of skipped
	// epochs. Inflation epochs are skipped when [types.Params.InflationEnabled]
	// is false so that gaps in the active status of inflation don't mess up the
	// polynomial computation. It allows inflation to smoothly be toggled on and
	// off.
	NumSkippedEpochs collections.Sequence

	// Params stores module-specific parameters that specify the blockchain token
	// economics, token release schedule, maximum supply, and whether or not
	// inflation is enabled on the network.
	Params collections.Item[types.Params]
}

